class Solution:
    def punishmentNumber(self, n: int) -> int:
        from functools import lru_cache

        def valid(i: int) -> bool:
            s = str(i * i)
            m = len(s)

            @lru_cache(None)
            def dfs(pos: int, rem: int) -> bool:
                if pos == m:
                    return rem == 0
                for j in range(pos + 1, m + 1):
                    val = int(s[pos:j])
                    if val > rem:
                        break
                    if dfs(j, rem - val):
                        return True
                return False

            return dfs(0, i)

        total = 0
        for i in range(1, n + 1):
            if valid(i):
                total += i * i
        return total
