Idea:
- Build a graph where indices are nodes and there’s an edge between i and j if nums[i] and nums[j] share a prime factor (>1).
- Use DSU (Union-Find) to connect indices that share any prime factor.
- Factor numbers efficiently with a smallest-prime-factor (SPF) sieve.
- Edge case: if any number is 1 (and n > 1), it cannot connect to any other node.

Python implementation:

from typing import List

class Solution:
    def canTraverseAllPairs(self, nums: List[int]) -> bool:
        n = len(nums)
        if n == 1:
            return True
        if any(x == 1 for x in nums):
            return False

        maxv = max(nums)

        # Build SPF (smallest prime factor) sieve up to maxv
        spf = list(range(maxv + 1))
        for i in range(2, int(maxv ** 0.5) + 1):
            if spf[i] == i:  # i is prime
                for j in range(i * i, maxv + 1, i):
                    if spf[j] == j:
                        spf[j] = i

        # DSU
        parent = list(range(n))
        rank = [0] * n

        def find(x: int) -> int:
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a: int, b: int):
            ra, rb = find(a), find(b)
            if ra == rb:
                return
            if rank[ra] < rank[rb]:
                parent[ra] = rb
            elif rank[ra] > rank[rb]:
                parent[rb] = ra
            else:
                parent[rb] = ra
                rank[ra] += 1

        # Map each prime factor to the first index that had it
        first_idx_of_prime = {}

        for i, val in enumerate(nums):
            x = val
            # factor into distinct primes using spf
            while x > 1:
                p = spf[x]
                # remove all occurrences of p
                while x % p == 0:
                    x //= p
                if p in first_idx_of_prime:
                    union(i, first_idx_of_prime[p])
                else:
                    first_idx_of_prime[p] = i

        root0 = find(0)
        for i in range(1, n):
            if find(i) != root0:
                return False
        return True

Complexity:
- Building SPF: O(M log log M), M = max(nums) ≤ 1e5
- Factorization per number: O(log M) amortized using SPF
- DSU operations: near O(1) amortized
Overall: O(n log M + M log log M), with O(n + M) space.

Approach:
- Let dp[j] be the maximum number of jumps to reach index j from index 0.
- Initialize dp[0] = 0 and all other dp[j] = -1 (unreachable).
- For each j from 1 to n−1, check all i < j. If dp[i] != -1 and |nums[j] − nums[i]| ≤ target, update dp[j] = max(dp[j], dp[i] + 1).
- Return dp[n−1] (it remains −1 if unreachable).

Time complexity: O(n^2)
Space complexity: O(n)

Python:
def maximumJumps(nums, target):
    n = len(nums)
    dp = [-1] * n
    dp[0] = 0
    for j in range(1, n):
        for i in range(j):
            if dp[i] != -1 and abs(nums[j] - nums[i]) <= target:
                dp[j] = max(dp[j], dp[i] + 1)
    return dp[-1]

Java:
public int maximumJumps(int[] nums, int target) {
    int n = nums.length;
    int[] dp = new int[n];
    Arrays.fill(dp, -1);
    dp[0] = 0;
    for (int j = 1; j < n; j++) {
        for (int i = 0; i < j; i++) {
            if (dp[i] != -1) {
                long diff = (long) nums[j] - nums[i];
                if (Math.abs(diff) <= target) {
                    dp[j] = Math.max(dp[j], dp[i] + 1);
                }
            }
        }
    }
    return dp[n - 1];
}

You need the longest contiguous subarray that:
- starts with an even number,
- alternates parity at each step,
- and all elements are ≤ threshold.

A single-pass O(n) solution keeps the current valid length and last parity, resetting/restarting when a rule breaks.

Python:
def longestAlternatingSubarray(nums, threshold):
    best = 0
    cur = 0
    last_parity = None  # 0 even, 1 odd; None means no active window

    for x in nums:
        if x > threshold:
            cur = 0
            last_parity = None
            continue

        if cur == 0:
            if (x & 1) == 0:
                cur = 1
                last_parity = 0
                best = max(best, cur)
        else:
            p = x & 1
            if p != last_parity:
                cur += 1
                last_parity = p
                best = max(best, cur)
            else:
                if p == 0:  # can restart at this even
                    cur = 1
                    last_parity = 0
                    best = max(best, cur)
                else:       # odd can't start
                    cur = 0
                    last_parity = None

    return best

Java:
public int longestAlternatingSubarray(int[] nums, int threshold) {
    int best = 0, cur = 0;
    int lastParity = -1; // -1 none, 0 even, 1 odd

    for (int x : nums) {
        if (x > threshold) {
            cur = 0;
            lastParity = -1;
            continue;
        }

        if (cur == 0) {
            if ((x & 1) == 0) {
                cur = 1;
                lastParity = 0;
                best = Math.max(best, cur);
            }
        } else {
            int p = x & 1;
            if (p != lastParity) {
                cur++;
                lastParity = p;
                best = Math.max(best, cur);
            } else {
                if (p == 0) { // restart at this even
                    cur = 1;
                    lastParity = 0;
                    best = Math.max(best, cur);
                } else {      // odd can't start
                    cur = 0;
                    lastParity = -1;
                }
            }
        }
    }

    return best;
}

